-- Database initialization script for Banjara Travel Project\n\nCREATE TABLE users (\n    user_id SERIAL PRIMARY KEY,\n    username VARCHAR(50) NOT NULL UNIQUE,\n    password VARCHAR(255) NOT NULL,\n    email VARCHAR(100) NOT NULL UNIQUE,\n    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP\n);\n\nCREATE TABLE vehicles (\n    vehicle_id SERIAL PRIMARY KEY,\n    vehicle_type VARCHAR(50) NOT NULL,\n    vehicle_model VARCHAR(100),\n    vehicle_capacity INT,\n    price_per_day DECIMAL(10, 2) NOT NULL,\n    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP\n);\n\nCREATE TABLE bookings (\n    booking_id SERIAL PRIMARY KEY,\n    user_id INT REFERENCES users(user_id) ON DELETE CASCADE,\n    vehicle_id INT REFERENCES vehicles(vehicle_id) ON DELETE CASCADE,\n    booking_date TIMESTAMP DEFAULT CURRENT_TIMESTAMP,\n    start_date DATE NOT NULL,\n    end_date DATE NOT NULL,\n    total_amount DECIMAL(10, 2) NOT NULL\n);\n\nCREATE TABLE payments (\n    payment_id SERIAL PRIMARY KEY,\n    booking_id INT REFERENCES bookings(booking_id) ON DELETE CASCADE,\n    payment_date TIMESTAMP DEFAULT CURRENT_TIMESTAMP,\n    amount DECIMAL(10, 2) NOT NULL,\n    payment_method VARCHAR(50) NOT NULL\n);\n\nCREATE TABLE reviews (\n    review_id SERIAL PRIMARY KEY,\n    user_id INT REFERENCES users(user_id) ON DELETE CASCADE,\n    vehicle_id INT REFERENCES vehicles(vehicle_id) ON DELETE CASCADE,\n    rating INT CHECK (rating >= 1 AND rating <= 5),\n    review_text TEXT,\n    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP\n);\n\nCREATE TABLE packages (\n    package_id SERIAL PRIMARY KEY,\n    package_name VARCHAR(100) NOT NULL,\n    package_description TEXT,\n    price DECIMAL(10, 2) NOT NULL,\n    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP\n);\n\nCREATE TABLE travel_items (\n    item_id SERIAL PRIMARY KEY,\n    package_id INT REFERENCES packages(package_id) ON DELETE CASCADE,\n    item_name VARCHAR(100) NOT NULL,\n    item_description TEXT,\n    item_price DECIMAL(10, 2) NOT NULL\n);\n\n-- Add any additional required relationships or constraints if needed